```typescript
import { NextResponse } from "next/server";
import { z } from "zod";

// Internal imports (follow import ordering guidelines in docs)
import { prisma } from "@rlm-saas/database";
import { requireAuth } from "@/lib/auth";

const querySchema = z.object({
  page: z.preprocess(
    (val) => {
      if (val === undefined || val === null) return 1;
      if (typeof val === "string") return parseInt(val, 10);
      return val;
    },
    z.number().int().positive().default(1)
  ),
  limit: z.preprocess(
    (val) => {
      if (val === undefined || val === null) return 50;
      if (typeof val === "string") return parseInt(val, 10);
      return val;
    },
    z.number().int().positive().max(100).default(50)
  ),
  search: z.string().optional(),
  sort: z.enum(["created_asc", "created_desc", "name_asc", "name_desc"]).optional(),
});

export async function GET(request: Request): Promise<Response> {
  try {
    // 1. Authenticate (per documented route handler pattern)
    await requireAuth();

    // 2. Parse and validate query params using Zod
    const url = new URL(request.url);
    const raw = {
      page: url.searchParams.get("page") ?? undefined,
      limit: url.searchParams.get("limit") ?? undefined,
      search: url.searchParams.get("search") ?? undefined,
      sort: url.searchParams.get("sort") ?? undefined,
    };

    const parsed = querySchema.parse(raw);
    const page = parsed.page;
    const limit = parsed.limit;
    const search = parsed.search;
    const sort = parsed.sort;

    // 3. Build Prisma where/orderBy based on validated params
    const where = search
      ? {
          OR: [
            { email: { contains: search, mode: "insensitive" } },
            { name: { contains: search, mode: "insensitive" } },
          ],
        }
      : undefined;

    const orderBy =
      sort === "created_asc"
        ? { createdAt: "asc" }
        : sort === "created_desc"
        ? { createdAt: "desc" }
        : sort === "name_asc"
        ? { name: "asc" }
        : sort === "name_desc"
        ? { name: "desc" }
        : { createdAt: "desc" }; // default

    // 4. Delegate to Prisma to fetch users + total count
    const [users, total] = await Promise.all([
      prisma.user.findMany({
        where,
        orderBy,
        take: limit,
        skip: (page - 1) * limit,
        select: {
          id: true,
          name: true,
          email: true,
          image: true,
          createdAt: true,
          // add other allowed fields as needed
        },
      }),
      prisma.user.count({ where }),
    ]);

    const totalPages = Math.ceil(total / limit);

    // 5. Return response (using NextResponse as shown in import examples)
    return NextResponse.json(
      {
        users,
        total,
        page,
        totalPages,
      },
      { status: 200 }
    );
  } catch (error) {
    // Minimal error handling here; the docs show using handleError in examples,
    // but its import/location isn't specified in the provided docs. Return a 400/500 response instead.
    console.error("GET /api/users error:", error);
    const message = error instanceof z.ZodError ? error.errors : "Internal server error";
    const status = error instanceof z.ZodError ? 400 : 500;
    return NextResponse.json({ error: message }, { status });
  }
}
```

